SELECT task_id, AVG(hours) AS average_hours
FROM task_hours
GROUP BY task_id;

SELECT SUM(hours) AS total_hours_logged
FROM task_hours
WHERE team_member_id = 1 AND task_id = 1;

SELECT project_name AS "Project Name"
FROM projects
WHERE LENGTH(end_date) - LENGTH(start_date) = (SELECT MAX(LENGTH(end_date) - LENGTH(start_date)) FROM projects);
